def _mono() -> QFont:
    f = QFont("Consolas")
    f.setStyleHint(QFont.Monospace)
    f.setPointSize(10)
    return f


class WorkspaceDialog(QDialog):
    """List the workspace folders; add more or remove selected ones."""

    def __init__(self, parent):
        super().__init__(parent)
        self.setWindowTitle("Manage Workspace")
        self.resize(540, 360)
        v = QVBoxLayout(self)
        v.addWidget(QLabel("The agent works on these folders:"))
        self.listbox = QListWidget()
        self.listbox.addItems(core.get_workspace())
        v.addWidget(self.listbox, 1)
        row = QHBoxLayout()
        add_btn = QPushButton("Add Folder...")
        rm_btn = QPushButton("Remove Selected")
        add_btn.clicked.connect(self.on_add)
        rm_btn.clicked.connect(self.on_remove)
        row.addWidget(add_btn)
        row.addWidget(rm_btn)
        row.addStretch(1)
        v.addLayout(row)
        bb = QDialogButtonBox(QDialogButtonBox.Ok)
        bb.accepted.connect(self.accept)
        v.addWidget(bb)

    def _refresh(self):
        self.listbox.clear()
        self.listbox.addItems(core.get_workspace())

    def on_add(self):
        path = QFileDialog.getExistingDirectory(
            self, "Add a folder to the workspace")
        if path:
            core.add_workspace_folder(path)
            self._refresh()

    def on_remove(self):
        i = self.listbox.currentRow()
        if i < 0:
            return
        folders = core.get_workspace()
        del folders[i]
        core.set_workspace(folders)
        self._refresh()


class SkillEditDialog(QDialog):
    """Edit one skill: name + description (the routing hint shown to the agent)
    + body (loaded on demand). Tick 'user-only' to make it /<name>-only."""

    def __init__(self, parent, title, name="", text="", description="",
                 disable_model_invocation=False):
        super().__init__(parent)
        self.setWindowTitle(title)
        self.resize(520, 400)
        v = QVBoxLayout(self)
        row = QHBoxLayout()
        row.addWidget(QLabel("Name:"))
        self.name = QLineEdit(name)
        row.addWidget(self.name, 1)
        v.addLayout(row)
        v.addWidget(QLabel("Description (what it does + when to use it; the only "
                           "part the agent sees until it loads the skill):"))
        self.description = QLineEdit(description)
        v.addWidget(self.description)
        self.manual = QCheckBox("Apply only when the user types /<name> "
                                "(not auto-selected by the agent)")
        self.manual.setChecked(bool(disable_model_invocation))
        v.addWidget(self.manual)
        body_row = QHBoxLayout()
        body_row.addWidget(
            QLabel("Skill body (the full instructions — loaded on demand):"), 1)
        load_btn = QPushButton("Load from .md…")
        load_btn.clicked.connect(self.on_load_md)
        body_row.addWidget(load_btn)
        v.addLayout(body_row)
        self.text = QPlainTextEdit(text)
        v.addWidget(self.text, 1)
        bb = QDialogButtonBox(QDialogButtonBox.Ok | QDialogButtonBox.Cancel)
        bb.accepted.connect(self.accept)
        bb.rejected.connect(self.reject)
        v.addWidget(bb)

    def on_load_md(self):
        path, _ = QFileDialog.getOpenFileName(
            self, "Import SKILL.md", "",
            "Markdown (*.md *.markdown *.txt);;All files (*)")
        if not path:
            return
        try:
            with open(path, encoding="utf-8", errors="ignore") as f:
                s = core.parse_skill_md(f.read())
        except OSError as e:
            QMessageBox.warning(self, "Import failed", str(e))
            return
        if s["name"]:
            self.name.setText(s["name"])
        if s["description"]:
            self.description.setText(s["description"])
        self.manual.setChecked(s["disable_model_invocation"])
        self.text.setPlainText(s["text"])

    def values(self):
        return {"name": self.name.text().strip() or "skill",
                "description": self.description.text().strip(),
                "text": self.text.toPlainText().strip(),
                "disable_model_invocation": self.manual.isChecked()}


class SkillsDialog(QDialog):
    """Add / edit / remove an agent's skills at runtime. Changes persist to
    skills.json and apply on the next run."""

    def __init__(self, parent):
        super().__init__(parent)
        self.setWindowTitle("Manage Skills")
        self.resize(620, 500)
        v = QVBoxLayout(self)
        self._agents = core.list_skill_agents()
        row = QHBoxLayout()
        row.addWidget(QLabel("Agent:"))
        self.agent = QComboBox()
        self.agent.addItems(self._agents or ["(none)"])
        self.agent.currentIndexChanged.connect(lambda _i: self._reload())
        row.addWidget(self.agent, 1)
        v.addLayout(row)
        self.listbox = QListWidget()
        v.addWidget(self.listbox, 1)
        h = QHBoxLayout()
        for label, slot in (("Add...", self.on_add), ("Edit...", self.on_edit),
                            ("Remove", self.on_remove)):
            b = QPushButton(label)
            b.clicked.connect(slot)
            h.addWidget(b)
        h.addStretch(1)
        v.addLayout(h)
        bb = QDialogButtonBox(QDialogButtonBox.Ok)
        bb.accepted.connect(self.accept)
        v.addWidget(bb)
        self._reload()

    def _cur_agent(self):
        return self._agents[self.agent.currentIndex()] if self._agents else None

    def _reload(self):
        a = self._cur_agent()
        self._items = list(core.skills_for(a)) if a else []
        self.listbox.clear()
        self.listbox.addItems(
            [(s.get("name") or "skill") + ": "
             + (s.get("text") or "").replace(chr(10), " ")[:48]
             for s in self._items])

    def on_add(self):
        a = self._cur_agent()
        if not a:
            return
        dlg = SkillEditDialog(self, "Add Skill")
        if dlg.exec() == QDialog.Accepted and dlg.values()["text"]:
            r = dlg.values()
            core.add_skill(a, r["name"], r["text"], r["description"],
                           r["disable_model_invocation"])
            self._reload()

    def on_edit(self):
        a = self._cur_agent()
        i = self.listbox.currentRow()
        if not a or i < 0:
            return
        s = self._items[i]
        dlg = SkillEditDialog(self, "Edit Skill", s.get("name", ""),
                              s.get("text", ""), s.get("description", ""),
                              s.get("disable_model_invocation", False))
        if dlg.exec() == QDialog.Accepted and dlg.values()["text"]:
            r = dlg.values()
            core.update_skill(a, i, r["name"], r["text"], r["description"],
                              r["disable_model_invocation"])
            self._reload()

    def on_remove(self):
        a = self._cur_agent()
        i = self.listbox.currentRow()
        if a and i >= 0:
            core.remove_skill(a, i)
            self._reload()


# (label shown in the combo, internal grader type). The runtime grade() supports
# all of these; multi-assertion `checks` arrays are authored in the JSONL/config.
_GRADE_TYPES = [
    ("contains (substring)", "contains"),
    ("equals (exact)", "equals"),
    ("not contains", "not_contains"),
    ("contains all (comma list)", "contains_all"),
    ("contains any (comma list)", "contains_any"),
    ("starts with", "starts_with"),
    ("ends with", "ends_with"),
    ("regex", "regex"),
    ("not regex", "not_regex"),
    ("is JSON", "is_json"),
    ("JSON has keys (comma list)", "json_has_keys"),
    ("numeric (approx value)", "numeric"),
    ("similar (fuzzy)", "similar"),
    ("length (min,max)", "length"),
    ("judge (LLM rubric)", "judge"),
]
_STRING_TYPES = {"contains", "equals", "not_contains", "contains_all",
                 "contains_any", "starts_with", "ends_with"}


class EvalCaseEditDialog(QDialog):
    """Add / edit one eval case: an input plus a typed grader (substring, exact,
    regex, JSON checks, numeric, fuzzy similarity, length, LLM rubric, …). A
    single assertion here; multi-assertion `checks` arrays are authored in the
    evals/*.jsonl file or config.json."""

    def __init__(self, parent, title, case=None):
        super().__init__(parent)
        self.setWindowTitle(title)
        self.resize(540, 480)
        case = case or {}
        v = QVBoxLayout(self)
        row = QHBoxLayout()
        row.addWidget(QLabel("ID:"))
        self.cid = QLineEdit(case.get("id", ""))
        row.addWidget(self.cid, 1)
        v.addLayout(row)
        v.addWidget(QLabel("Input (sent to the agent):"))
        self.input = QPlainTextEdit(case.get("input", ""))
        v.addWidget(self.input, 1)
        row2 = QHBoxLayout()
        row2.addWidget(QLabel("Grade by:"))
        self.grade = QComboBox()
        self.grade.addItems([lbl for lbl, _ in _GRADE_TYPES])
        row2.addWidget(self.grade)
        self.case_sensitive = QCheckBox("case sensitive")
        row2.addWidget(self.case_sensitive)
        row2.addStretch(1)
        v.addLayout(row2)
        v.addWidget(QLabel("Expected value (substring / regex / criterion / "
                           "number / comma-list; ignored for 'is JSON'):"))
        self.expected = QPlainTextEdit()
        v.addWidget(self.expected, 1)
        row3 = QHBoxLayout()
        row3.addWidget(QLabel("Option:"))
        self.option = QLineEdit()
        self.option.setPlaceholderText("similar: threshold 0-1  |  numeric: "
                                       "tolerance  |  length: min,max")
        row3.addWidget(self.option, 1)
        v.addLayout(row3)
        self._preload(case)
        bb = QDialogButtonBox(QDialogButtonBox.Ok | QDialogButtonBox.Cancel)
        bb.accepted.connect(self.accept)
        bb.rejected.connect(self.reject)
        v.addWidget(bb)

    def _preload(self, case):
        # Prefer an explicit single assertion, else the first `checks` entry,
        # else the legacy expected_output / expected_regex / judge fields.
        a = None
        if case.get("type"):
            a = case
        elif isinstance(case.get("checks"), list) and case["checks"]:
            a = case["checks"][0]
        elif case.get("judge"):
            a = {"type": "judge", "value": case["judge"]}
        elif case.get("expected_regex"):
            a = {"type": "regex", "value": case["expected_regex"]}
        elif case.get("expected_output") is not None:
            a = {"type": "contains", "value": case.get("expected_output", "")}
        if not a:
            return
        t = a.get("type", "contains")
        for i, (_lbl, ty) in enumerate(_GRADE_TYPES):
            if ty == t:
                self.grade.setCurrentIndex(i)
                break
        self.case_sensitive.setChecked(bool(a.get("case_sensitive")))
        self.expected.setPlainText(str(a.get("value", "")))
        if t == "length":
            lo, hi = a.get("min"), a.get("max")
            self.option.setText(("" if lo is None else str(lo)) + ","
                                + ("" if hi is None else str(hi)))
        elif t == "similar" and a.get("threshold") is not None:
            self.option.setText(str(a["threshold"]))
        elif t in ("numeric", "close") and a.get("tolerance") is not None:
            self.option.setText(str(a["tolerance"]))

    def values(self):
        t = _GRADE_TYPES[self.grade.currentIndex()][1]
        case = {"id": self.cid.text().strip() or "case",
                "input": self.input.toPlainText().strip(), "type": t}
        val = self.expected.toPlainText().strip()
        opt = self.option.text().strip()
        if t == "is_json":
            pass                                  # no value needed
        elif t == "length":
            lo, _sep, hi = opt.partition(",")
            if lo.strip().lstrip("-").isdigit():
                case["min"] = int(lo.strip())
            if hi.strip().lstrip("-").isdigit():
                case["max"] = int(hi.strip())
        else:
            case["value"] = val
            if opt:
                try:
                    if t == "similar":
                        case["threshold"] = float(opt)
                    elif t == "numeric":
                        case["tolerance"] = float(opt)
                except ValueError:
                    pass
        if self.case_sensitive.isChecked() and t in _STRING_TYPES:
            case["case_sensitive"] = True
        return case


